import java.io.*;
import org.apache.commons.text.StringEscapeUtils; // Using Apache Commons Text library for HTML escaping

public class XSSSecureCode {
    public static void main(String[] args) throws IOException {
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));

        System.out.println("Enter your name: ");
        String name = reader.readLine();

        String safeName = StringEscapeUtils.escapeHtml4(name); // HTML escape the user input

